/*
 * Copyright (C) 2016 - present by OpenGamma Inc. and the OpenGamma group of companies
 *
 * Please see distribution for license.
 */
package com.opengamma.strata.product.credit;

import java.io.Serializable;
import java.time.LocalDate;
import java.util.Map;
import java.util.NoSuchElementException;

import org.joda.beans.Bean;
import org.joda.beans.ImmutableBean;
import org.joda.beans.JodaBeanUtils;
import org.joda.beans.MetaBean;
import org.joda.beans.MetaProperty;
import org.joda.beans.gen.BeanDefinition;
import org.joda.beans.gen.ImmutableDefaults;
import org.joda.beans.gen.ImmutablePreBuild;
import org.joda.beans.gen.PropertyDefinition;
import org.joda.beans.impl.direct.DirectFieldsBeanBuilder;
import org.joda.beans.impl.direct.DirectMetaBean;
import org.joda.beans.impl.direct.DirectMetaProperty;
import org.joda.beans.impl.direct.DirectMetaPropertyMap;

import com.google.common.collect.ImmutableSet;
import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.Resolvable;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.date.BusinessDayAdjustment;
import com.opengamma.strata.basics.date.DayCount;
import com.opengamma.strata.basics.date.DayCounts;
import com.opengamma.strata.basics.date.DaysAdjustment;
import com.opengamma.strata.basics.schedule.PeriodicSchedule;
import com.opengamma.strata.basics.schedule.Schedule;
import com.opengamma.strata.basics.schedule.SchedulePeriod;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.product.Product;
import com.opengamma.strata.product.common.BuySell;

/**
 * A CDS (portfolio) index tranche product.
 * <p>
 * A CDS tranche is a slice of a CDS index portfolio defined by attachment and detachment points.
 * The protection buyer periodically pays fixed coupons to the protection seller until the expiry,
 * and in return, the protection buyer receives compensation for losses within the attachment and detachment points.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * Whether the CDS tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection, where the fixed coupon is paid
   * and the protection is received in the event of default.
   * A value of 'Sell' implies selling protection, where the fixed coupon is received
   * and the protection is paid in the event of default.
   */
  @PropertyDefinition(validate = "notNull")
  private final BuySell buySell;
  /**
   * The underlying CDS index.
   * <p>
   * The tranche is defined on top of this CDS index.
   */
  @PropertyDefinition(validate = "notNull")
  private final CdsIndex underlyingIndex;
  /**
   * The attachment point.
   * <p>
   * This is the point at which the tranche protection starts, expressed as a decimal (0.0 to 1.0).
   * For example, 0.03 means the tranche absorbs losses starting from 3% of the portfolio notional.
   */
  @PropertyDefinition(validate = "ArgChecker.inRange")
  private final double attachmentPoint;
  /**
   * The detachment point.
   * <p>
   * This is the point at which the tranche protection ends, expressed as a decimal (0.0 to 1.0).
   * For example, 0.06 means the tranche protection covers losses up to 6% of the portfolio notional.
   */
  @PropertyDefinition(validate = "ArgChecker.inRange")
  private final double detachmentPoint;

  //-------------------------------------------------------------------------
  /**
   * Creates an instance of a CDS tranche.
   *
   * @param buySell  buy or sell
   * @param underlyingIndex  the underlying CDS index
   * @param attachmentPoint  the attachment point (between 0.0 and 1.0)
   * @param detachmentPoint  the detachment point (between 0.0 and 1.0)
   * @return the instance
   */
  public static CdsTranche of(
      BuySell buySell,
      CdsIndex underlyingIndex,
      double attachmentPoint,
      double detachmentPoint) {

    ArgChecker.inRange(attachmentPoint, 0.0, 1.0, "attachmentPoint");
    ArgChecker.inRange(detachmentPoint, 0.0, 1.0, "detachmentPoint");
    ArgChecker.isTrue(
        detachmentPoint > attachmentPoint,
        "detachmentPoint ({}) must be greater than attachmentPoint ({})",
        detachmentPoint,
        attachmentPoint);

    return new CdsTranche(buySell, underlyingIndex, attachmentPoint, detachmentPoint);
  }

  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
  }

  @ImmutablePreBuild
  private static void preBuild(Builder builder) {
    if (builder.attachmentPoint >= 0.0 && builder.detachmentPoint > builder.attachmentPoint) {
      // validation done
    }
  }

  //-------------------------------------------------------------------------
  @Override
  public ImmutableSet<Currency> allCurrencies() {
    return underlyingIndex.allCurrencies();
  }

  //-------------------------------------------------------------------------
  /**
   * Resolves this tranche using the specified reference data.
   *
   * @param refData  the reference data
   * @return the resolved CDS tranche
   */
  @Override
  public ResolvedCdsTranche resolve(ReferenceData refData) {
    ResolvedCdsIndex resolvedIndex = underlyingIndex.resolve(refData);
    return new ResolvedCdsTranche(
        buySell,
        resolvedIndex,
        attachmentPoint,
        detachmentPoint);
  }

  //------------------------- AUTOGENERATED START -------------------------
  /**
   * The meta-bean for {@code CdsTranche}.
   * @return the meta-bean, not null
   */
  public static CdsTranche.Meta meta() {
    return CdsTranche.Meta.INSTANCE;
  }

  static {
    MetaBean.register(CdsTranche.Meta.INSTANCE);
  }

  /**
   * The serialization version id.
   */
